	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

type DepartmentReportRow struct {
	GroupValue      string
	UserCount       int
	TotalActivities int
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
		CreatedAt:   time.Now(),
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build placeholders for usernames
	placeholders := make([]string, len(usernames))
	args := make([]interface{}, 0)

	for i, username := range usernames {
		placeholders[i] = "?"
		args = append(args, username)
	}

	// Add date range parameters
	args = append(args, startDate, endDate)

	// Build WHERE clause
	whereClause := fmt.Sprintf("u.username IN (%s) AND a.created_at BETWEEN ? AND ?", strings.Join(placeholders, ","))

	// Add action type filter if provided
	if actionTypeFilter != "" {
		whereClause += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	// Build SQL query
	sql := fmt.Sprintf(`
		SELECT u.display_name, a.action_type, COUNT(*) as total_actions, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE %s
		GROUP BY u.display_name, a.action_type
	`, whereClause)

	var results []UserActivitySummary
	_, err := o.Raw(sql, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}

	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build placeholders for departments
	placeholders := make([]string, len(departments))
	args := make([]interface{}, 0)

	for i, dept := range departments {
		placeholders[i] = "?"
		args = append(args, dept)
	}

	// Build SQL query based on groupByField
	var fieldName string
	switch groupByField {
	case "department":
		fieldName = "u.department"
	case "role":
		fieldName = "u.role"
	case "display_name":
		fieldName = "u.display_name"
	}

	sql := fmt.Sprintf(`
		SELECT %s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY %s
	`, fieldName, strings.Join(placeholders, ","), fieldName)

	var rows []DepartmentReportRow
	_, err := o.Raw(sql, args...).QueryRows(&rows)
	if err != nil {
		return nil, err
	}

	results := make([]map[string]interface{}, len(rows))
	for i, row := range rows {
		results[i] = map[string]interface{}{
			"group_value":      row.GroupValue,
			"user_count":       row.UserCount,
			"total_activities": row.TotalActivities,
		}
	}

	return results, nil
}

