// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build the WHERE clause for usernames
	placeholders := ""
	args := make([]interface{}, 0)

	for i, username := range usernames {
		if i > 0 {
			placeholders += ", "
		}
		placeholders += "?"
		args = append(args, username)
	}

	// Add date range filters
	args = append(args, startDate, endDate)

	// Build the query
	query := fmt.Sprintf(`
		SELECT u.display_name, a.action_type, COUNT(*) as total_actions, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ?`, placeholders)

	// Add action type filter if provided
	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	var results []UserActivitySummary
	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}

	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build the WHERE clause for departments
	placeholders := ""
	args := make([]interface{}, 0)

	for i, dept := range departments {
		if i > 0 {
			placeholders += ", "
		}
		placeholders += "?"
		args = append(args, dept)
	}

	// Build the query with dynamic GROUP BY
	query := fmt.Sprintf(`
		SELECT u.%s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s`, groupByField, placeholders, groupByField)

	var results []DepartmentReportRow
	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	// Convert to map format
	mapResults := make([]map[string]interface{}, 0)
	for _, row := range results {
		mapResults = append(mapResults, map[string]interface{}{
			"group_value":      row.GroupValue,
			"user_count":       row.UserCount,
			"total_activities": row.TotalActivities,
		})
	}

	return mapResults, nil
}

